def dijkstra_path(graph, start, goal):
    import heapq

    dist = {start: 0}
    prev = {}
    heap = [(0, start)]

    while heap:
        d, u = heapq.heappop(heap)
        if u == goal:
            break
        for v, w in graph.get(u, []):
            nd = d + w
            if v not in dist or nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(heap, (nd, v))

    if goal not in dist:
        return float('inf'), []

    path = []
    cur = goal
    while cur != start:
        path.append(cur)
        cur = prev[cur]
    path.append(start)
    path.reverse()

    return dist[goal], path
