def eval_expr(s):
    """Evaluate an integer expression with +, -, *, parentheses, unary minus."""
    s = s.strip()
    if not s:
        raise ValueError("Empty expression")

    pos = [0]  # mutable index tracker

    def peek():
        return s[pos[0]]

    def advance():
        ch = s[pos[0]]
        pos[0] += 1
        return ch

    def parse_number():
        start = pos[0]
        while pos[0] < len(s) and s[pos[0]].isdigit():
            pos[0] += 1
        if pos[0] == start:
            raise ValueError(f"Expected digit at position {start}")
        return int(s[start:pos[0]])

    def parse_unary():
        ch = peek()
        if ch == '-':
            advance()
            val = parse_unary()  # allow nested unary minus like --5
            return -val
        elif ch == '+':
            advance()
            return parse_unary()
        else:
            return parse_number()

    def parse_mul():
        left = parse_unary()
        while peek() in ('*', '/'):
            op = advance()
            right = parse_unary()
            if op == '*':
                left *= right
            elif op == '/':
                if right == 0:
                    raise ZeroDivisionError("division by zero")
                left //= right
        return left

    def parse_add():
        left = parse_mul()
        while peek() in ('+', '-'):
            op = advance()
            right = parse_mul()
            if op == '+':
                left += right
            elif op == '-':
                left -= right
        return left

    result = parse_add()
    if pos[0] != len(s):
        raise ValueError(f"Unexpected character at position {pos[0]}: '{s[pos[0]]}'")
    return result
