def strongly_connected_components(graph):
    """Return all SCCs of the directed graph defined by `graph`.

    Each SCC is returned as a frozenset (treated as a set). Nodes that
    appear only as neighbours are included automatically.
    """
    # Build adjacency list and collect every node (source + neighbour)
    nodes = set()
    for src, nbrs in graph.items():
        nodes.add(src)
        for n in nbrs:
            nodes.add(n)

    # Tarjan's algorithm
    index_counter = [0]
    stack = []
    lowlink = {}
    index = {}
    on_stack = set()
    sccs = []

    def strongconnect(v):
        index[v] = index_counter[0]
        lowlink[v] = index_counter[0]
        index_counter[0] += 1
        stack.append(v)
        on_stack.add(v)

        for w in graph.get(v, ()):
            if w not in index:
                strongconnect(w)
                lowlink[v] = min(lowlink[v], lowlink[w])
            elif w in on_stack:
                lowlink[v] = min(lowlink[v], index[w])

        if lowlink[v] == index[v]:
            scc = set()
            while True:
                w = stack.pop()
                on_stack.discard(w)
                scc.add(w)
                if w == v:
                    break
            sccs.append(scc)

    for n in nodes:
        if n not in index:
            strongconnect(n)

    return sccs
